const Q_CHEMISTRY_2016=[{"id": "objective>Chemistry>2016>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2KClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> → 2KCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 3O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> <br/> In the reaction above, the catalyst used is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">MnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fe</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ni</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equation of the reaction: <br/> 2KClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> → 2KCl + 30<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>  <br/>  * The reaction above is one of the ways oxygen can be produced in the laboratory  <br/>  - It involves the thermal decomposition of KClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> to release all its oxygen when heated above its melting point 368<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C. In the presence of Manganese (IV) oxide, when acts as a catalyst. </div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2016>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many electrons are present in the potassium ion?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20</div>", "<div style=\"font-family:Cambria;font-size:17px;\">39</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18</div>", "<div style=\"font-family:Cambria;font-size:17px;\">19</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Potassium atom loses one electron to form potassium ion  <br/> K - e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> <br/>  K - K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> + e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>;  <br/>  Potassium atoms has 19 electrons; its ion has 18 electrons.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2016>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the maximum mass of crystals that will be obtained from a 20cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> solution of Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>.10H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O, if its solubility at 25<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C is 45g in 1dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of water.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.025g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.045g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.900g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.500g</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> The volume of the solution = 20cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 0.02dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>  <br/>  The solubility of the salt = 45gdm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>  <br/>  The mass that will crystalize out = ?  <br/>  Solubility (in gdm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>) = mass/volume of solution   <br/>  S = m/v;  <br/> Sv = m;  <br/> 0.02 x 45 = 0.90g </div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>2016>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Graphite conducts electricity due to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the presence of mobile electrons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its crystalline structure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its inert nature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its high melting point</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Graphite conducts electricity due to the presence of mobile electrons. In graphite, each carbon atom is covalently bonded to three other carbon atoms. This leaves one electron per carbon atom free to move and carry an electric charge. This is why graphite can conduct electricity.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2016>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the mass of silver deposited when a current of 1.8A is passed through a solution of a silver salt for 90 minutes. [Ag = 108, F = 96500Cmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>].</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.18g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.10g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.88g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">108.78g</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> The current, I = 1.8A  <br/> Time, T = 90minutes = 5400s  <br/>  Equation of the reaction: Ag<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> + e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Ag<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span>  <br/>  1F → 108g   <br/>  That is, 1 Farad of electricity produces 108g of silver.  <br/>  Recall that Q = It   <br/>  Q = 1.8 x 5400 = 9720C   <br/>  1Farad = 96500C  <br/>  96500C produces 108  <br/>  9720C will produce xg: 96500/9720 = 108/x   <br/>  x = 10.878 = 10.88g </div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2016>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The acid used as a mild antiseptic is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">trioxnitrate(V)acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrochloric acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">boric acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanoic acid</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Boric acid is used as a mild antiseptic. It has antifungal, antiviral and antibacterial properties. It is often used in the treatment of minor burns, cuts and abrasions.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2016>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation number of nitrogen in HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">+3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+4</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given:  <br/>  HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>: This is a compound; conventionally the oxidation number of any compound is zero(0)  <br/>  The oxidation number of HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, (0) IS EQUAL TO SUM OF THE OXIDATION NUMBERS OF THE CONSTITUENT ELEMENT   <br/>  0 = h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">ON</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(ON)</span> + N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">ON</span>  <br/>  O = = +1 + 2(-2) + X  <br/>  X = 3 </div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2016>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The rate of a chemical reaction usually increases with the concentration of the reactants because the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">frequency of collision of the reactants increases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reactants have higher kinetic energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">activation energy of the reaction becomes lower </div>", "<div style=\"font-family:Cambria;font-size:17px;\">distance between reacting species increases </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in concentration usually cause a corresponding increase in the frequency of collision of reactants. Hence, an increase in reaction rate.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2016>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When heated, the metal that will burn with a lilac flame is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Na</div>", "<div style=\"font-family:Cambria;font-size:17px;\">K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ca</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Potassium usually burns with lilac flame. This colour is used as an indication for the presence of potassium ion during flame test.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALKALI METALS"}, {"id": "objective>Chemistry>2016>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following halogens is the least reactive?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Br<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Iodine (I2) is the least reactive halogen. This is because reactivity in halogens decreases down the group in the periodic table. Fluorine is the most reactive halogen because it is at the top of the group, while iodine, being at the bottom, is the least reactive.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HALOGENS"}, {"id": "objective>Chemistry>2016>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The increase in the carbon content of steel will increase its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">appearance and hardness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hardness and conductivity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conductivity and brittleness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">brittleness and hardness</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon in steel helps to increase its brittleness and hardness. <br/>  <br/> Medium-carbon steels have from 0.30 to 0.45 percent carbon. Increased carbon means increased hardness and tensile strength, decreased ductility, and more difficult machining.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALLOY"}, {"id": "objective>Chemistry>2016>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The product obtained when sodium is burnt in excess air is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaOH</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When sodium is heated in air, it burns with a golden yellow flame to form sodium peroxide in excess supply of air or oxygen.  <br/>  2Na + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">excess</span> → Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(s)</span></div>", "topic": "METALS AND THEIR COMPOUNDS : ALKALI METALS"}, {"id": "objective>Chemistry>2016>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A concentrated solution containing H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>,Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>, OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> and Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">- </span>was electrolyzed using platinum electrodes. The ion that will be discharged at the cathode is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In electrolysis, the ion that will be discharged at the cathode is the cation, which is the positively charged ion. In this case, we are having two cations that are Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> and H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>. However, Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> will be discharged in preference to H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> because Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> is less electropositive than H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> and also it is lower in the electrochemical series than H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>.</div>", "topic": "ELECTROLYSIS : ELECTROLYTES AND NON-ELECTROLYTES"}, {"id": "objective>Chemistry>2016>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is re-used in the solvay process?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaCl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the Solvay process, ammonia (NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>) is used to produce sodium carbonate. The ammonia is recovered in a later step of the process and is reused, making the process more economical and environmentally friendly.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2016>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The presence of water in cobalt(II)chloride will change it from </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pink to blue </div>", "<div style=\"font-family:Cambria;font-size:17px;\">blue to white </div>", "<div style=\"font-family:Cambria;font-size:17px;\">blue to pink </div>", "<div style=\"font-family:Cambria;font-size:17px;\">white to blue</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is a test of for the presence of water. The presence of water in cobalt (II) chloride will change it from blue to pink.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2016>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The product obtained when excess ethanol is made to react with concentrated H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> at a temperature below 170<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethoxyethene </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethoxyethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">epoxyethane</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If ethanol is in excess and the temperature is low, (below 170<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C), it will react with the acid, H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH → C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OC<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> (Ethoxy ethane) + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2016>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The separation method that can be used to separate an insoluble solid from a liquid is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">precipitation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decantation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distillation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Decantation is a process used to separate mixtures, usually a solid and a liquid. In this process, the mixture is allowed to settle and the liquid is poured off, leaving the solid behind. This method is often used when the solid is insoluble, or does not dissolve in the liquid.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2016>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Insoluble salts can be prepared by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">neutralization of an alkali by an acid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the action of dilute acid on a metal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">direct combination of two elements</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the action of dilute acid on a trioxocarbonate(IV)</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Insoluble salts can be prepared using two methods:  <br/>  1. By double decomposition.  <br/>  2. Combination of constituent elements </div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2016>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The cohesive forces between gas molecules are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">in random motion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">negligible</div>", "<div style=\"font-family:Cambria;font-size:17px;\">independent of temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfectly elastic </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cohesive forces between gas molecules are negligibel; i.e the molecules are independent of each other.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2016>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The separation technique that is extensively employed in sugar industries is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">centrifugation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chromatography </div>", "<div style=\"font-family:Cambria;font-size:17px;\">crystallization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distillation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Crystallization is employed in the sugar industry as it is applied in the production of sugar. <br/>  <br/> The beet and cane sugar industries use evaporation to concentrate the dilute sugar steam, as extracted from the beet or cane, up to the final concentration prior to crystallization, itself a form of evaporation.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2016>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The shell of an atom that will accomodate a maximum number of 18 electrons is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">M</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">L</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The maximum number of electrons that a shell can accomodate is given by: <br/> No of electrons = 2(n)^2; Where n is the position of the shell from nuclei  <br/>  <br/> For K = Me = 2(1)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 2  <br/> L = Me = 2(2)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 8  <br/> M = Me = 2(3)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 18  <br/> N = Me = 2(4)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 32 <br/> O = Me = 2(5)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 50  <br/> P = Me = 2(6)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 72 <br/> Q = Me = 2(7)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 98 </div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2016>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ammonia gas can be dried using</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ammonia gas is an alkaline gas; it can be dried with drying agent that is also alkaline as this will not lead to any reaction  <br/>  <br/> However, H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>, P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span> and CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> will react with ammonia to form (NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>, NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>PO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> and NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl and Ca(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, hence H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>, P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span> and CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> cannot be used as a drying agent for ammonia because they react with ammonia gas.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2016>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The electron configuration of a metalloid is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span> has 13 electrons that is aluminium (a metal) <br/>  1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> has 14 electrons that is silicon; (a metalloid)  <br/>  1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> has 15 electrons that is phosphorous (a non-metal)  <br/>  1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> has 16 electrons that is oxygen (a non-metal)</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2016>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many moles are there in 30g of CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>? <br/> [Ca = 40, C = 12 , O = 16]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.30</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.20</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given:  <br/>  The mass of CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = 30g  <br/> The molar mass of CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = 100gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>  <br/> recall that: Number of mole = mass/molar mass = 30/100 = 0.3mol. </div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2016>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the diagram above, <strong>X</strong> is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">methane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethyne</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethene</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The set-up is the laboratory preparation of methane   <br/>  CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COONa <span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Sodium ethanoate</span> + NaOH <span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Sodalime</span> → Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> + CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2016>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Argon is used in gas-filled electric bulbs because it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">catalyzes the burning of the filament</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gives coloured light</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prolongs the life of the filament</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is light in weight</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Argon is used in gas-filled electric bulb because it prolongs the life of the filament by preventing the oxidation of the filament through providing an inert atmosphere.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2016>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Propene undergoes addition reaction with chlorine because it is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">saturated </div>", "<div style=\"font-family:Cambria;font-size:17px;\">polar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unsaturated</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aromatic</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Propene is an unsaturated hydrocarbon because it contains a carbon-carbon double bond. Unsaturated hydrocarbons undergo addition reactions because the pi bond between the carbon atoms can be broken to allow new atoms to add to the carbon atoms.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2016>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>-CH(OH)-CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-CH(CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)-CHO <br/> The IUPAC nomenclature of the compound is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2-methyl-4-hydroxylpentanal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-hydroxyl-4-methylpentanal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4-methyl-2-hydroxylpentanal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4-hydroxyl-2-methylpentanal</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2016/28.png\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The functional group (-CHO) makes the compound an alkanal.  <br/> The longest continous carbon chain is 5, hence the root name is pentanal.  <br/> It has two attachments, methyl, CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>on the second carbon and hydroxyl on the fourth carbon. The compound above is  <br/> 4-hydroxyl-2-methyl pentanal.   <br/>  *Note that hydroxyl comes before methyl since 'H' comes before 'M' in the alphabet.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2016>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An organic compound of relative molecular mass 136.0, on analysis was found to contain 52.0% carbon, 13.3% hydrogen and 34.7% oxygen. What is its molecular?  <br/> [C = 12, H = 1, O = 16]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">18</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">24</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> The RMM of the compound = 136,  <br/>  % compositions of constituents: C = 52%; H=13.3%; O = 34.7%  <br/>  The molecula formula = ? <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> Carbon</td><td style=\"border:1px solid black;text-align:center;\"> Hydrogen</td><td style=\"border:1px solid black;text-align:center;\"> Oxygen  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">% composition</td><td style=\"border:1px solid black;text-align:center;\"> 52%</td><td style=\"border:1px solid black;text-align:center;\"> 13.3%</td><td style=\"border:1px solid black;text-align:center;\"> 34.7%  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Mass(use % comp.)</td><td style=\"border:1px solid black;text-align:center;\"> 52g</td><td style=\"border:1px solid black;text-align:center;\"> 13.3g</td><td style=\"border:1px solid black;text-align:center;\"> 34.7g  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Number of moles</td><td style=\"border:1px solid black;text-align:center;\"> 52/12</td><td style=\"border:1px solid black;text-align:center;\"> 13.3/1</td><td style=\"border:1px solid black;text-align:center;\"> 34.7/16 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> 4.3</td><td style=\"border:1px solid black;text-align:center;\"> 13.3</td><td style=\"border:1px solid black;text-align:center;\"> 2.2 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Divide by the smallest mole</td><td style=\"border:1px solid black;text-align:center;\"> 4.3/2.2 = 2</td><td style=\"border:1px solid black;text-align:center;\"> 13.3/2.2= 6</td><td style=\"border:1px solid black;text-align:center;\"> 2.2/2.2 = 1</td></tr></table></div> <br/>  <br/>  The empirical formula = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>O  <br/>  Recall that: Molecular formula = (Empirical formula)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span> <br/> But RMM of (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>O)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span> = (2 x RAM of C) + (6 x RAM of H) + (1 x RAM of O)n <br/> =(2 x 12) + (6 x 1) + (1 x 16)n <br/> =(24 + 6 + 16)n  <br/> =(46)n <br/> But the RMM of the compound = 136 <br/> Therefore (46)n = 136 <br/> n=2.9=3 <br/> (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>O)n = Molecular formula <br/> (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>O)3= (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">18</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> <br/> Molecular formula = (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">18</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2016>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following will only undergo substitution reaction?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">9</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">20</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">18</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">20</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">9</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">18</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Substitution reactions are characteristic of saturated hydrocarbons, which have all single bonds and are filled to capacity with hydrogen atoms. C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">9</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">20</span> is a saturated hydrocarbon, and thus, will only undergo substitution reactions.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2016>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → 2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> <br/>  Calculate the enthalphy change in the reaction above, if the enthalphy of SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> is -297 kJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>is 0 kJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> and SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span>is -395kJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">-98kJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">+98 kJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">-692 kJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">-196 kJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equation of the reaction  <br/>  <br/> 2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>  <br/> Given: ∆Hf(SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) = -297KJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> ∆Hf (O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) = 0 ∆Hf (SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>) = -395KJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Recall that:  <br/> ∆Hreaction = Ʃ∆H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">nproduct</span> - Ʃ∆H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">nReactants</span>   <br/> Where n is the number of moles. <br/> ∆H = 2(-395) - (2(-297))  <br/>  = -790 + 594 = -196KJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>.</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2016>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following has the highest boiling point?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Propane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hexane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Octane</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a homologous series, the higher the molar mass, the higher the boiling point. In a family like alkane the higher the molar mass, the higher the boiling point  <br/> In the options, we have members of the alkane family. Octane has the highest molar mass.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2016>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When elements X and Y with electron configurations 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span> and 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> respectively are combined chemically, the bond is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">metallic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coordinate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">covalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrovalent</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given two elements, X and Y,   <br/>  X has elements that is, Lithium (a metal) <br/>  <br/>  Y has 17 electrons that is, chlorine (a non metal), the bond between a metal and a non-metal is electrovalent (ionic).</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2016>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following can be used as a cooking gas?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The formula C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span> represents butane, which is a common component of cooking gas. The other options represent other hydrocarbons, but these are not typically used as cooking gases.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2016>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">11</span>Na + Y → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">24</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">11</span>Na  <br/> In the equation above, <strong>Y</strong> is likely to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an electron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a proton</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a neutron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> the equation of the reaction: <br/> <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">11</span>Na + y → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">24</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">11</span>Na   <br/>  y → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">24</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">11</span>na - <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">11</span>Na   <br/>  balance up the mass atomic number.  <br/>  11 - 11 = 0 <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span>Y where x and y are the mass number and the atomic number of y respectively  <br/> x = 1 and y = 0. Y is a neutron   <br/>  Neutron, <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>n has an atomic number of 0 and a mass number of 1.</div>", "topic": "NUCLEAR CHEMISTRY : NUCLEAR REACTIONS"}, {"id": "objective>Chemistry>2016>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>→ 2HI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>, ΔH = +ve <br/>  From the equation above, it can be inferred that bond-breaking energies are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">greater than bond-forming energies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less than bond-forming energies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal and opposite to bond forming energies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal to bond-forming energies</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The enthalpy of the reaction is positive, i.e, an endothermic reaction. This means that the bond breaking requires absorbtion of heat and bond formation requires the release of heat.</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2016>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Catalytic cracking is widely used than thermal cracking because it involves low </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">temperature and higher grade petrol is obtained </div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature and gives purer products </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pressure and yields more of lubricants </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pressure and higher grade petrol is obtained </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Catalytic cracking is widely used than cracking because it involves low temperature and higher grade petrol is obtained.</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2016>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sodium hydroxide is not kept in zinc containers because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">zinc is a transition metal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium hydroxide changes colour to orange </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium hydroxide becomes deliquescent </div>", "<div style=\"font-family:Cambria;font-size:17px;\">zinc readily dissolves in it </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sodium hydroxide (NaOH) is a strong base and is corrosive. It reacts with zinc (Zn), a reactive metal, to form sodium zincate and hydrogen gas. Therefore, sodium hydroxide is not stored in zinc containers because the zinc would dissolve in it.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2016>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The boiling point of a liquid can be increased only by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">atmospheric pressure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">further heating </div>", "<div style=\"font-family:Cambria;font-size:17px;\">impurities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vapour pressure </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Impurities cause the elevation of the boiling point of a hither to pure liquid substance.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : BIOLING AND MELTING POINTS"}, {"id": "objective>Chemistry>2016>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A substance can be said to be hygroscopic when it absorbs</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">moisture from the atmosphere to form a solution </div>", "<div style=\"font-family:Cambria;font-size:17px;\">heat from the surroundings </div>", "<div style=\"font-family:Cambria;font-size:17px;\">moisture from the atmosphere without dissolving it </div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon(IV)oxide from the atmosphere without forming a solution </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A substance is said to be hygroscopic if it absorbs moisture from the atmosphere but does not dissolve in it. These substances are used as drying agents or desiccants because they can remove moisture from the air without becoming part of the solution.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2016>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ratio of carbon to hydrogen in sucrose is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6:11</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sucrose has a molecula formula.  <br/>  C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">22</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">11</span> : The carbon to hydrogen ratio is 12:22 = 6:11 </div>", "topic": "ORGANIC COMPOUNDS : CARBOHYDRATES"}, {"id": "objective>Chemistry>2016>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an exothermic reaction,a decrease in temperature of a system would lead to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the value of equilibrium constant and greater products yield</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the value of equilibrium constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the value of equilibrium constant and greater products yield</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the value of equilibrium constant</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Le Chatelier's principle, if a system at equilibrium is subjected to a change in temperature, pressure, or concentration of components, the system will shift its equilibrium position to counteract the effect of the disturbance. In an exothermic reaction, a decrease in temperature would shift the equilibrium to the right (towards the products) to produce more heat, thus increasing the value of the equilibrium constant and leading to a greater yield of products.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2016>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The fraction of petroleum that distils over in the temperature range of 40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C to 200<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">kerosene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">petrol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gas oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bitumen</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Petroleum is a mixture of hydrocarbons that are separated by the process of fractional distillation. The fraction that distills over in the temperature range of 40 to 200 degrees Celsius is petrol.</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2016>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A characteristic common to electrovalent compounds is that they </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">are soluble in organic solvents </div>", "<div style=\"font-family:Cambria;font-size:17px;\">contain only molecules </div>", "<div style=\"font-family:Cambria;font-size:17px;\">have high melting points</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are non-electrolytes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Electrovalent compounds, also known as ionic compounds, are formed by the transfer of electrons from one atom to another. This results in the formation of ions which are held together by strong electrostatic forces of attraction, giving them high melting points.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2016>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 2ZnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> → CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + 2Zn<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> <br/> In the reaction above, the substances undergoing reduction is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon(IV)oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zinc</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equation of the reaction  <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> + 2ZnO → CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + 2Zn<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> <br/>  <br/>  Zinc is reduced in the reaction above.  <br/>  Reduction can be defined as the reduction in oxidation number   <br/>  At the reactant, the oxidation number of zinc is +2, in the product side, the oxidation number of zinc is zero </div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>2016>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following occurs when concentrated sodium hydroxide solution is electrolyzed using platinum electrodes?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen is discharged at the node </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The electrolyte becomes more acidic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The electrolyte becomes more alkaline</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The concentration of the electrolyte remains unchanged</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the electrolysis of NaOH, the concentrations of Na<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> and OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> increase as water is removed making the electrolyte more alkaline. </div>", "topic": "ELECTROLYSIS : ELECTROLYTES AND NON-ELECTROLYTES"}, {"id": "objective>Chemistry>2016>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Butene and butyne can be distinguished in the laboratory by the use of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bromine water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">silver trioxonitrate(V)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium hydroxide solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">potassium tetraoxomanganate(VII)</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Butene and butyne are distinguished from eachother through use of silver trioxonitrate (V), since butyne is a terminal alkyne.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2016>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a basic salt?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ZnSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mg(OH)NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zn(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>.10H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mg(OH)NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> <br/> * Salts with the structure X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>(OH)M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>  are called basis salt; because of the presence of hydroxyl ion (OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>).</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2016>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Pollution of a river by organic water is harmful to aquatic organisms because of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the presence of heavy metal ions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the reduction in the amount of dissolved oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the level of sediments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in bacterial population</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pollution of a river by organic waste is harmful to aquatic organisms because of the reduction in the amount of dissolved oxygen. The decomposition of organic waste by bacteria in the water uses up oxygen, reducing the amount available for aquatic life.</div>", "topic": "ENVIRONMENTAL POLLUTION : WATER POLLUTION"}, {"id": "objective>Chemistry>2016>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the solubility of 10.1g of potassium trioxonitrate(V) dissolved in 50g  of distilled water at 25<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C <br/> [K = 39, N = 14, O = 16]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10.0 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.0 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.1 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> The mass of potassium trioxonitrate (V), KNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = 10.1g  <br/> The mass of water = 50g = 50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of water, since the density of water is 1 gcm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>  <br/> 50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 0.05dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Let the volume of water be the volume of solution = 0.05dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Molar mass of KNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = 39 + 14 + 48 = 101gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Number of mole = mass/molar mass = 10.1/101 = 0.1mol <br/> Recall that: <br/> Solubility (in moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>) = Number of mole/volume of solution = 0.1/0.05 = 2moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>.</div>", "topic": "SOLUBILITY : SOLVENTS"}];
